void DriftLFO::tick(double dt)
{
    if (!active)
        return;
    for (auto& lfo : lfos)
    {
        if (lfo.target == 0 || lfo.depth == 0.0f)
            continue;
        lfo.phase += static_cast<double>(lfo.rate) * dt;
        if (lfo.phase >= 1.0)
            lfo.phase -= std::floor(lfo.phase);
    }
}

